const CryptoJS = require('crypto-js');

function base64url(source) {
  let encoded = CryptoJS.enc.Base64.stringify(source);
  return encoded.replace(/=/g, '').replace(/\+/g, '-').replace(/\//g, '_');
}

const secret = insomnia.environment.get('jwt_secret') || "CarrefourFluxoCaixaSecretKey2024!@#$%";

const header = {
  alg: "HS256",
  typ: "JWT"
};

const now = Math.floor(Date.now() / 1000);
const payload = {
  sub: "avaliador-local",
  name: "Avaliador Local",
  role: "comerciante",
  iss: "FluxoCaixa",
  aud: "FluxoCaixaAPI",
  iat: now,
  nbf: now - 5,
  exp: now + 3600,
  jti: "xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx".replace(/[xy]/g, function(c) {
    var r = Math.random() * 16 | 0, v = c == 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  })
};

const stringifiedHeader = CryptoJS.enc.Utf8.parse(JSON.stringify(header));
const encodedHeader = base64url(stringifiedHeader);

const stringifiedPayload = CryptoJS.enc.Utf8.parse(JSON.stringify(payload));
const encodedPayload = base64url(stringifiedPayload);

const tokenSubject = `${encodedHeader}.${encodedPayload}`;
const signature = CryptoJS.HmacSHA256(tokenSubject, secret);
const encodedSignature = base64url(signature);

const jwt = `${tokenSubject}.${encodedSignature}`;

insomnia.environment.set("token_jwt", jwt);

